class RangeModule:
    def __init__(self):
        self.ranges = []

    def addRange(self, left: int, right: int):
        self.ranges.append((left, right))

    def queryRange(self, left: int, right: int):
        for range_tuple in self.ranges:
            if left >= range_tuple[0] and right <= range_tuple[1]:
                return True
        return False

    def removeRange(self, left: int, right: int):
        for index, range_tuple in enumerate(self.ranges):
            if left >= range_tuple[0] and right <= range_tuple[1]:
                del self.ranges[index]

